sql:
SELECT position, COUNT(player_id) AS player_count
FROM player
GROUP BY position;

SELECT player_name, height
FROM player
WHERE team = 'New England Patriots';

SELECT player_name, draft_year
FROM player
ORDER BY draft_year DESC;

SELECT AVG(home_score) AS average_home_score
FROM game
WHERE season = 2021 AND season_type = 'REG';

SELECT player_name, position, experience_years
FROM player
WHERE status = 'active';

SELECT AVG(height) AS average_height
FROM player
WHERE team = 'Niners';

external_knowledge:
- 'Patriots' refers to the New England Patriots team;
- 'Giants' refers to the New York Giants team;
- 'current players' means players with an 'active' status.

